1	------------------------------------------------------------------------------
2	--  Copyright (c) 2020 by Enclustra GmbH, Switzerland
3	--  All rights reserved.
4	--  Authors: Oliver Bruendler
5	------------------------------------------------------------------------------
6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This entity allows preventing synthesis tools from optimizing away any
11	-- number of input/output signals. To do so, only four I/O pins are required.
12	-- This functionality can be used to to synthesis tests runs for design-parts
13	-- that have more I/Os available than any real chip.
14	
15	--
16	--       4 Pins       CLK
17	--          |          |
18	--          |          |
19	--          |         _|_
20	--          |         \./
21	--          |          V                    +-----------+
22	--+-------------------------+               |           |
23	--|                         |               |           |
24	--| psi_common_dont_opt     |-------------- |           |
25	--|                         |-------------- |           |
26	--|                         |-------------- |    DUT    |
27	--|                         |-------------- |           |
28	--+-------------------------+               |           |
29	--                             N-inputs     |           |
30	--                             N-outputs    +-----------+
31	
32	library ieee;
33	use ieee.std_logic_1164.all;
34	use ieee.numeric_std.all;
35	
36	entity psi_common_dont_opt is
37	  generic( from_dut_width_g : positive := 8;                                         -- Number of device under test output bits (going to psi_common_dont_opt)
38	           to_dut_width_g   : positive := 16);                                       -- Number of device under test input bits (connected to psi_common_dont_opt*)
39	  port(   clk_i             : in    std_logic;                                       -- system clock
40	          pin_io            : inout std_logic_vector(3 downto 0);                    -- I/O pins required to prevent optimization
41	          dat_o             : out   std_logic_vector(to_dut_width_g - 1 downto 0);   -- signal from DUT
42	          dat_i             : in    std_logic_vector(from_dut_width_g - 1 downto 0));-- signal to DUT
43	end entity;
44	
45	architecture rtl of psi_common_dont_opt is
46	
47	  type two_process_t is record
48	    ToDutShiftReg   : std_logic_vector(dat_o'range);
49	    ToDutLatchReg   : std_logic_vector(dat_o'range);
50	    FromDutShiftReg : std_logic_vector(dat_i'range);
51	  end record;
52	
53	  signal r, r_next : two_process_t;
54	
55	begin
56	
57	  p_comb : process(pin_io, dat_i, r)
58	    variable v : two_process_t;
59	  begin
60	    -- *** Hold variables stable ***
61	    v := r;
62	
63	    -- *** Implementation ***
64	    if pin_io(0) = '1' then
65	      v.ToDutLatchReg := r.ToDutShiftReg;
66	    end if;
67	    v.ToDutShiftReg := r.ToDutShiftReg(r.ToDutShiftReg'high - 1 downto 0) & pin_io(1);
68	
69	    if pin_io(2) = '1' then
70	      v.FromDutShiftReg := dat_i;
71	    else
72	      v.FromDutShiftReg := r.FromDutShiftReg(r.FromDutShiftReg'high - 1 downto 0) & '0';
73	    end if;
74	
75	    -- *** Assign signal ***
76	    r_next <= v;
77	  end process;
78	
79	  pin_io(0) <= 'Z';
80	  pin_io(1) <= 'Z';
81	  pin_io(2) <= 'Z';
82	  pin_io(3) <= r.FromDutShiftReg(r.FromDutShiftReg'high);
83	
84	  dat_o <= r.ToDutLatchReg;
85	
86	  p_seq : process(clk_i)
87	  begin
88	    if rising_edge(clk_i) then
89	      r <= r_next;
90	    end if;
91	  end process;
92	
93	end architecture;

